      valid_positive_integer?(snapshot["deadline_at_ms"]) and
      valid_positive_integer?(snapshot["deadline_generation"]) and
      valid_role_capabilities?(role_capabilities) and valid_recording?(snapshot["recording"]) and
      is_list(participants) and length(participants) <= 500 and
      Enum.all?(participants, &valid_participant?(&1, role_capabilities)) and
      is_list(requests) and length(requests) <= 500 and
      Enum.all?(requests, &valid_admission_request?/1) and
      valid_snapshot_collections?(
        snapshot["status"],
        host_id,
        participants,
        requests,
        snapshot["recording"]
      ) and frame_within_limit?(snapshot, @limits["snapshotEncodedBytes"])
  end

  defp valid_snapshot?(_snapshot), do: false

  defp valid_participant?(
         %{
           "participant_session_id" => id,
           "display_name" => name,
           "hand_raised" => raised,
           "admission_revision" => admission_revision,
           "role" => role,
           "eligible_roles" => eligible,
           "capabilities" => capabilities
         } = participant,
         role_capabilities
       ) do
    exact_keys?(participant, [
      "participant_session_id",
      "display_name",
      "hand_raised",
      "admission_revision",
      "role",
      "eligible_roles",
      "capabilities"
    ]) and valid_uuid?(id) and bounded_string?(name, 1, 256) and is_boolean(raised) and
      valid_positive_integer?(admission_revision) and role in @roles and
      non_empty_unique_list?(eligible) and length(eligible) <= 3 and
      Enum.all?(eligible, &(&1 in @roles)) and role in eligible and
      (role != "host" or "cohost" in eligible) and capabilities == role_capabilities[role]
  end

  defp valid_participant?(_participant, _role_capabilities), do: false

  defp valid_admission_request?(
         %{
           "admission_request_id" => request_id,
           "participant_session_id" => participant_id,
           "display_name" => name,
           "initial_role" => role,
           "eligible_roles" => eligible,
           "expires_at_ms" => expires_at
         } = request
       ),
       do:
         exact_keys?(request, [
           "admission_request_id",
           "participant_session_id",
           "display_name",
           "initial_role",
           "eligible_roles",
           "expires_at_ms"
         ]) and valid_uuid?(request_id) and valid_uuid?(participant_id) and
           bounded_string?(name, 1, 256) and role in @roles and non_empty_unique_list?(eligible) and
           length(eligible) <= 3 and Enum.all?(eligible, &(&1 in @roles)) and role in eligible and
           (role != "host" or "cohost" in eligible) and valid_positive_integer?(expires_at)

  defp valid_admission_request?(_request), do: false

  defp valid_role_capabilities?(
         %{"host" => host, "cohost" => cohost, "participant" => participant} = roles
       ),
       do:
         exact_keys?(roles, ["host", "cohost", "participant"]) and
           Enum.all?(
             [host, cohost, participant],
             &(unique_list?(&1) and length(&1) <= 16 and
                 Enum.all?(&1, fn capability -> capability in @capabilities end))
           )

  defp valid_role_capabilities?(_roles), do: false
  defp valid_recording?(nil), do: true

  defp valid_recording?(
         %{"recording_id" => id, "status" => status, "failure_code" => failure_code} = recording
       ),
       do:
         exact_keys?(recording, ["recording_id", "status", "failure_code"]) and valid_uuid?(id) and
           status in ["starting", "recording", "stopping", "stopped", "failed"] and
           (is_nil(failure_code) or bounded_string?(failure_code, 1, 96)) and
           status == "failed" == not is_nil(failure_code)

  defp valid_recording?(_recording), do: false

  defp valid_snapshot_collections?(status, host_id, participants, requests, recording) do
    participant_ids = Enum.map(participants, & &1["participant_session_id"])
    request_ids = Enum.map(requests, & &1["admission_request_id"])
    candidate_ids = Enum.map(requests, & &1["participant_session_id"])

    unique_list?(participant_ids) and unique_list?(request_ids) and unique_list?(candidate_ids) and
      MapSet.disjoint?(MapSet.new(participant_ids), MapSet.new(candidate_ids)) and
      valid_snapshot_state?(status, host_id, participants, requests, recording)
  end

  defp valid_snapshot_state?("ended", host_id, participants, requests, recording),
    do: is_nil(host_id) and participants == [] and requests == [] and is_nil(recording)

  defp valid_snapshot_state?("active", host_id, [], _requests, _recording), do: is_nil(host_id)

  defp valid_snapshot_state?("active", host_id, participants, _requests, _recording) do
    hosts = Enum.filter(participants, &(&1["role"] == "host"))
    valid_uuid?(host_id) and length(hosts) == 1 and hd(hosts)["participant_session_id"] == host_id
  end

  defp valid_snapshot_state?(_status, _host_id, _participants, _requests, _recording), do: false

  defp unique_list?(value) when is_list(value),
    do: MapSet.size(MapSet.new(value)) == length(value)

  defp unique_list?(_value), do: false
  defp non_empty_unique_list?(value), do: unique_list?(value) and value != []

  defp valid_event?(
         %{
           "name" => name,
           "event_id" => event_id,
           "base_revision" => base_revision,
           "revision" => revision,
           "schema_version" => schema_version,
           "resulting_state_digest" => digest,
           "payload" => payload
         } = frame
       ) do
    common = [
      "type",
      "stream",
      "name",
      "event_id",
      "base_revision",
      "revision",
      "schema_version",
      "resulting_state_digest",
      "payload"
    ]

    origin = Map.get(@event_origins, name)

    origin_keys =
      if origin == "command_or_external",
        do: ["command_id", "external_operation_id"],
        else: [
          if(origin == "command",
            do: "command_id",
            else:
              if(origin == "lifecycle", do: "lifecycle_intent_id", else: "external_operation_id")
          )
        ]

    Enum.any?(origin_keys, fn key ->
      exact_keys?(frame, common ++ [key]) and valid_origin_id?(key, frame[key])
    end) and frame["stream"] == "control" and valid_uuid?(event_id) and
      valid_revision_pair?(base_revision, revision) and valid_positive_integer?(schema_version) and
      valid_digest?(digest) and valid_event_payload?(name, payload) and
      frame_within_limit?(frame, @limits["encodedLiveEventBytes"])
  end

  defp valid_event?(_frame), do: false
  defp valid_origin_id?("command_id", id), do: valid_command_id?(id)
  defp valid_origin_id?(_key, id), do: valid_uuid?(id)

  defp valid_event_payload?(
         "participant_joined",
         %{
           "participant_session_id" => participant_session_id,
           "display_name" => display_name,
           "role" => role,
           "eligible_roles" => eligible_roles,
           "admission_revision" => admission_revision
         } = payload
       ) do
    exact_keys?(payload, [
      "participant_session_id",
      "display_name",
      "role",
      "eligible_roles",
      "admission_revision"
    ]) and valid_uuid?(participant_session_id) and bounded_string?(display_name, 1, 256) and
      role in ["host", "cohost", "participant"] and is_list(eligible_roles) and
      length(eligible_roles) <= 3 and Enum.all?(eligible_roles, &(&1 in @roles)) and
      valid_positive_integer?(admission_revision)
  end

  defp valid_event_payload?(
         "participant_left",
         %{"participant_session_id" => participant_session_id, "reason" => reason} = payload
       ) do
    exact_keys?(payload, ["participant_session_id", "reason"]) and
      valid_uuid?(participant_session_id) and reason in ["left", "removed"]
  end

  defp valid_event_payload?(
         "host_left_and_transferred",
         %{
           "departing_participant_session_id" => departing_participant_session_id,
           "successor_participant_session_id" => successor_participant_session_id
         } = payload
       ) do
    exact_keys?(payload, ["departing_participant_session_id", "successor_participant_session_id"]) and
      valid_uuid?(departing_participant_session_id) and
      valid_uuid?(successor_participant_session_id)
  end

  defp valid_event_payload?("session_ended", %{"reason" => reason} = payload) do
    exact_keys?(payload, ["reason"]) and
      reason in ["ended_by_participant", "tenant_recovery", "maximum_duration"]
  end

  defp valid_event_payload?(
         "hand_raised",
         %{"participant_session_id" => participant_session_id} = payload
       ) do
    exact_keys?(payload, ["participant_session_id"]) and valid_uuid?(participant_session_id)
  end

  defp valid_event_payload?(
         "hand_lowered",
         %{"participant_session_id" => participant_session_id} = payload
       ) do
    exact_keys?(payload, ["participant_session_id"]) and valid_uuid?(participant_session_id)
  end

  defp valid_event_payload?(
         "participant_display_name_changed",
         %{"participant_session_id" => participant_session_id, "display_name" => display_name} =
           payload
       ) do
    exact_keys?(payload, ["participant_session_id", "display_name"]) and
      valid_uuid?(participant_session_id) and bounded_string?(display_name, 1, 256)
  end

  defp valid_event_payload?("admission_policy_changed", %{"policy" => policy} = payload) do
    exact_keys?(payload, ["policy"]) and policy in ["open", "approval", "closed"]
  end

  defp valid_event_payload?(
         "participant_role_changed",
         %{"participant_session_id" => participant_session_id, "role" => role} = payload
       ) do
    exact_keys?(payload, ["participant_session_id", "role"]) and
      valid_uuid?(participant_session_id) and role in ["cohost", "participant"]
  end

  defp valid_event_payload?(
         "host_transferred",
         %{
           "previous_host_participant_session_id" => previous_host_participant_session_id,
           "new_host_participant_session_id" => new_host_participant_session_id
         } = payload
       ) do
    exact_keys?(payload, [
      "previous_host_participant_session_id",
      "new_host_participant_session_id"
    ]) and valid_uuid?(previous_host_participant_session_id) and
      valid_uuid?(new_host_participant_session_id)
  end

  defp valid_event_payload?(
         "deadline_changed",
         %{"deadline_at_ms" => deadline_at_ms, "deadline_generation" => deadline_generation} =
           payload
       ) do
    exact_keys?(payload, ["deadline_at_ms", "deadline_generation"]) and
      valid_positive_integer?(deadline_at_ms) and valid_positive_integer?(deadline_generation)
  end

  defp valid_event_payload?(
         "admission_requested",
         %{
           "admission_request_id" => admission_request_id,
           "participant_session_id" => participant_session_id,
           "display_name" => display_name,
           "initial_role" => initial_role,
           "eligible_roles" => eligible_roles,
           "expires_at_ms" => expires_at_ms
         } = payload
       ) do
    exact_keys?(payload, [
      "admission_request_id",
      "participant_session_id",
      "display_name",
      "initial_role",
      "eligible_roles",
      "expires_at_ms"
    ]) and valid_uuid?(admission_request_id) and valid_uuid?(participant_session_id) and
      bounded_string?(display_name, 1, 256) and initial_role in ["host", "cohost", "participant"] and
      is_list(eligible_roles) and length(eligible_roles) <= 3 and
      Enum.all?(eligible_roles, &(&1 in @roles)) and valid_positive_integer?(expires_at_ms)
  end

  defp valid_event_payload?(
         "admission_denied",
         %{"admission_request_id" => admission_request_id} = payload
       ) do
    exact_keys?(payload, ["admission_request_id"]) and valid_uuid?(admission_request_id)
  end

  defp valid_event_payload?(
         "admission_expired",
         %{"admission_request_id" => admission_request_id} = payload
       ) do
    exact_keys?(payload, ["admission_request_id"]) and valid_uuid?(admission_request_id)
  end

  defp valid_event_payload?(
         "participant_microphone_stopped",
         %{"participant_session_id" => participant_session_id} = payload
       ) do
    exact_keys?(payload, ["participant_session_id"]) and valid_uuid?(participant_session_id)
  end

  defp valid_event_payload?(
         "participant_camera_stopped",
         %{"participant_session_id" => participant_session_id} = payload
       ) do
    exact_keys?(payload, ["participant_session_id"]) and valid_uuid?(participant_session_id)
  end

  defp valid_event_payload?(
         "participant_screen_share_stopped",
         %{"participant_session_id" => participant_session_id} = payload
       ) do
    exact_keys?(payload, ["participant_session_id"]) and valid_uuid?(participant_session_id)
  end

  defp valid_event_payload?(
         "recording_status_changed",
         %{"recording_id" => recording_id, "status" => status, "failure_code" => failure_code} =
           payload
       ) do
    exact_keys?(payload, ["recording_id", "status", "failure_code"]) and valid_uuid?(recording_id) and
      status in ["starting", "recording", "stopping", "stopped", "failed"] and
      (is_nil(failure_code) or bounded_string?(failure_code, 1, 96))
  end

  defp valid_event_payload?(_name, _payload), do: false

  defp valid_replay_page?(
         %{
           "recovery_id" => recovery_id,
           "first_revision" => first_revision,
           "last_revision" => last_revision,
           "events" => events
         } = frame
       ) do
    exact_keys?(frame, ["type", "recovery_id", "first_revision", "last_revision", "events"]) and
      valid_uuid?(recovery_id) and is_list(events) and
      length(events) <= @limits["replayPageMaxEvents"] and
      frame_within_limit?(frame, @limits["replayPageEncodedBytes"]) and
      valid_replay_range?(events, first_revision, last_revision)
  end

  defp valid_replay_page?(_frame), do: false
  defp valid_replay_range?([], _first, _last), do: false

  defp valid_replay_range?([first | rest], first_revision, last_revision) do
    valid_event?(first) and first["revision"] == first_revision and
      Enum.reduce_while(rest, first, fn event, previous ->
        if valid_event?(event) and event["base_revision"] == previous["revision"],
          do: {:cont, event},
          else: {:halt, false}
      end)
      |> case do
        false -> false
        last -> last["revision"] == last_revision
      end
  end

  defp valid_ack?(
         %{
           "outcome" => "committed",
           "command_id" => id,
           "delivery" => delivery,
           "event_id" => event_id,
           "revision" => revision,
           "state_digest" => digest
         } = frame
       ),
       do:
         exact_keys?(frame, [
           "type",
           "command_id",
           "delivery",
           "outcome",
           "event_id",
           "revision",
           "state_digest"
         ]) and valid_ack_base?(id, delivery) and valid_uuid?(event_id) and
           valid_positive_integer?(revision) and valid_digest?(digest)

  defp valid_ack?(
         %{
           "outcome" => "satisfied",
           "command_id" => id,
           "delivery" => delivery,
           "revision" => revision,
           "state_digest" => digest
         } = frame
       ),
       do:
         exact_keys?(frame, [
           "type",
           "command_id",
           "delivery",
           "outcome",
           "revision",
           "state_digest"
         ]) and valid_ack_base?(id, delivery) and valid_non_negative_integer?(revision) and
           valid_digest?(digest)

  defp valid_ack?(
         %{"outcome" => outcome, "command_id" => id, "delivery" => delivery, "reason" => reason} =
           frame
       )
       when outcome in ["rejected", "command_id_conflict"],
       do:
         exact_keys?(frame, ["type", "command_id", "delivery", "outcome", "reason"]) and
           valid_ack_base?(id, delivery) and reason in @rejection_reasons and
           (outcome != "command_id_conflict" or reason == "command_id_conflict")

  defp valid_ack?(_frame), do: false

  defp valid_ack_base?(id, delivery),
    do: valid_command_id?(id) and delivery in ["original", "duplicate"]

  defp valid_projection?(
         %{
           "type" => "projection_snapshot",
           "stream" => stream,
           "projection_id" => projection_id,
           "sequence" => 0,
           "items" => items
         } = frame
       ) do
    exact_keys?(frame, ["type", "stream", "projection_id", "sequence", "items"]) and
      valid_uuid?(projection_id) and is_list(items) and
      length(items) <= projection_item_limit(stream) and
      Enum.all?(items, &valid_projection_item?(stream, &1)) and
      frame_within_limit?(frame, @limits["projectionSnapshotEncodedBytes"])
  end

  defp valid_projection?(
         %{
           "type" => "projection_event",
           "stream" => stream,
           "projection_id" => projection_id,
           "sequence" => sequence,
           "item" => item
         } = frame
       ) do
    exact_keys?(frame, ["type", "stream", "projection_id", "sequence", "item"]) and
      valid_uuid?(projection_id) and valid_positive_integer?(sequence) and
      valid_projection_item?(stream, item) and
      frame_within_limit?(frame, @limits["encodedLiveEventBytes"])
  end

  defp valid_projection?(_frame), do: false
  defp projection_item_limit("media"), do: 1_500
  defp projection_item_limit("presence"), do: 500
  defp projection_item_limit(_stream), do: -1

  defp valid_projection_item?(
         "media",
         %{
           "participant_session_id" => id,
           "source" => source,
           "enabled" => enabled,
           "publication_id" => publication_id
         } = item
       ),
       do:
         exact_keys?(item, ["participant_session_id", "source", "enabled", "publication_id"]) and
           valid_uuid?(id) and source in @media_sources and is_boolean(enabled) and
           (is_nil(publication_id) or bounded_string?(publication_id, 1, 256)) and
           enabled == not is_nil(publication_id)

  defp valid_projection_item?(
         "presence",
         %{
           "participant_session_id" => id,
           "state" => state,
           "speaking" => speaking,
           "active_speaker" => active
         } = item
       ),
       do:
         exact_keys?(item, ["participant_session_id", "state", "speaking", "active_speaker"]) and
           valid_uuid?(id) and state in @presence_states and is_boolean(speaking) and
           is_boolean(active) and (state != "disconnected" or (not speaking and not active))

  defp valid_projection_item?(_stream, _item), do: false

  defp valid_live_target_result?(
         %{"operation_id" => id, "name" => name, "outcome" => outcome, "error_code" => error_code} =
           frame
       ),
       do:
         exact_keys?(frame, ["type", "operation_id", "name", "outcome", "error_code"]) and
           valid_request_id?(id) and name in @live_target_names and
           outcome in @live_target_outcomes and
           (is_nil(error_code) or
              bounded_string?(error_code, 1, @limits["protocolErrorDetailBytes"]))

  defp valid_live_target_result?(_frame), do: false

  defp valid_directed_request_delivery?(
         %{
           "request_id" => id,
           "name" => name,
           "actor_participant_session_id" => actor_id,
           "expires_at_ms" => expires_at
         } = frame
       ),
       do:
         exact_keys?(frame, [
           "type",
           "request_id",
           "name",
           "actor_participant_session_id",
           "expires_at_ms"
         ]) and valid_request_id?(id) and name in @directed_request_names and
           valid_uuid?(actor_id) and valid_positive_integer?(expires_at)

  defp valid_directed_request_delivery?(_frame), do: false

  defp valid_directed_request_result?(%{"request_id" => id, "result" => result} = frame),
    do:
      exact_keys?(frame, ["type", "request_id", "result"]) and valid_request_id?(id) and
        result in @directed_request_results

  defp valid_directed_request_result?(_frame), do: false

  defp valid_cursor?(nil), do: true

  defp valid_cursor?(
         %{"revision" => revision, "state_schema_version" => version, "state_digest" => digest} =
           cursor
       ),
       do:
         exact_keys?(cursor, ["revision", "state_schema_version", "state_digest"]) and
           valid_non_negative_integer?(revision) and valid_positive_integer?(version) and
           valid_digest?(digest)

  defp valid_cursor?(_cursor), do: false
  defp valid_token?(value), do: bounded_string?(value, 0, @limits["tokenBytes"])

  defp valid_command_id?(value),
    do: bounded_string?(value, @limits["commandIdMinBytes"], @limits["commandIdMaxBytes"])

  defp valid_request_id?(value),
    do: bounded_string?(value, @limits["requestIdMinBytes"], @limits["requestIdMaxBytes"])

  defp bounded_string?(value, minimum, maximum),
    do: is_binary(value) and byte_size(value) >= minimum and byte_size(value) <= maximum

  defp valid_uuid?(value), do: is_binary(value) and value =~ @uuid
  defp valid_digest?(value), do: is_binary(value) and value =~ @digest
  defp valid_non_negative_integer?(value), do: is_integer(value) and value >= 0
  defp valid_positive_integer?(value), do: is_integer(value) and value >= 1

  defp valid_revision_pair?(base, revision),
    do: valid_non_negative_integer?(base) and revision == base + 1

  defp exact_keys?(map, keys) when is_map(map),
    do: map_size(map) == length(keys) and Enum.all?(keys, &Map.has_key?(map, &1))

  defp exact_keys?(_value, _keys), do: false
  defp frame_within_limit?(frame, limit), do: frame |> JSON.encode!() |> byte_size() <= limit
end
